		fac = new int[N];
		rest = new int[N];

		int x,y;
		for(x=0;x<N;++x)
		{
			fac[x] = x;
			rest[x] = 1;
		}

		for(x=2;x<N;++x)
		if(fac[x]==x)
		{
			ap.add(x);
			for(y=x+x;y<N;y+=x)
			if(fac[y]==y)
			{
				fac[y] = x;
				rest[y] = y/x;
			}
		}

		prime = new int[ap.size()];
		for(int i=0;i<prime.length;++i) prime[i] = ap.get(i);
	}



