    public static boolean[] getPrime(int N){
	boolean[] memo=new boolean[N+1];
	Arrays.fill(memo,true);
	memo[0]=false;
	memo[1]=false;
	for(int i=2;i*i<=N;i++){
	    if(memo[i]){
		for(int j=i*i;j<=N;j+=i){
		    memo[j]=false;
		}
	    }
	}
	return memo;
    }

