            for(int i=1;i<=n;i++)
                isPrime[i] = true;
            isPrime[1] = false;
            isPrime[2] = true;
            for(int i=2;i*i<=n;i++)
                for(int j=2*i;j<=n;j+=i)
                    isPrime[j] = false;
            int[] primes = new int[n];
            int cur = 0;
            for(int i=2;i<=n;i++)
                if (isPrime[i]) {
                    primes[cur] = i;
                    cur++;
                }
            int count = 0;
            for(int i=0;i<cur-1;i++) {
                if (primes[i] + primes[i+1] + 1 <= n && isPrime[primes[i] + primes[i+1] + 1])
                    count++;
            }
            if (count >= k)
                out.printf("YES");
            else
                out.printf("NO");


