    public int diffInEvenness(int n, int[] naturalNumbers) {       
        int even, odd, lastEvenIndex, lastOddIndex;
        even = odd = lastEvenIndex = lastOddIndex = 0;
        for (int i = 0; i < naturalNumbers.length; i++) {
            if((naturalNumbers[i] % 2) == 0) {
                even++;
                lastEvenIndex = i + 1;
            }
            else {
