	int solve(String a, int k){
		int n = a.length(), ret = 0;
		int temp[] = new int[n];
		for(int i = 0; i < n; i++) temp[(n + i - k) % n] = (a.charAt(i) == 'T') ? 1: 0;
		int left = 0, right = n - 1;
		while(left < right){
			while(temp[left] == 0) left++;
			while(temp[right] == 1) right--;
			if(left < right){
				int t = temp[left];
				temp[left] = temp[right];
				temp[right] = t;
				ret++;
			}
		}
		return ret;
	}

