    static class Testcase {
        HashMap<Integer, Integer> map;
        ArrayList<ArrayList<Integer>> adj;
        int[] arr;
        boolean[] vis;
        ArrayList<Integer> path;

        public void dfs(int v) {
            vis[v] = true;
            path.add(v);
            for (int u : adj.get(v)) {
                if (vis[u])
                    continue;
                dfs(u);
            }
        }

        public void solve(int test) {
            int n = in.nextInt(), a = in.nextInt(), b = in.nextInt();
            arr = new int[n];
            map = new HashMap<>();
            adj = new ArrayList<ArrayList<Integer>>();
            for (int i = 0; i < n; i++) {
                arr[i] = in.nextInt();
                map.put(arr[i], i);
                adj.add(new ArrayList<Integer>());
            }
            int[] ans = new int[n];
            if (a == b) {
                Arrays.fill(ans, 0);
                for (int i = 0; i < n; i++) {
                    if (!map.containsKey(a - arr[i])) {
                        out.println("NO");
                        return;
                    }
                }
            } else {
                int[] self = new int[n];
                Arrays.fill(self, -1);
                for (int i = 0; i < n; i++) {
                    if (map.containsKey(a - arr[i]) && a != 2 * arr[i])
                        adj.get(i).add(map.get(a - arr[i]));
                    if (map.containsKey(b - arr[i]) && b != 2 * arr[i])
                        adj.get(i).add(map.get(b - arr[i]));
                    if (2 * arr[i] == a)
                        self[i] = 0;
                    if (2 * arr[i] == b)
                        self[i] = 1;
                }

                vis = new boolean[n];
                path = new ArrayList<Integer>();

                for (int i = 0; i < n; i++) {
                    if (self[i] != -1 && !vis[i]) {
                        path.clear();
                        dfs(i);
                        if (path.size() % 2 == 1) {
                            ans[path.get(0)] = self[path.get(0)];
                            path.remove(0);
                        }
                        for (int j = 0; j + 1 < path.size(); j += 2) {
                            int cur = 0;
                            if (arr[path.get(j)] + arr[path.get(j + 1)] == b)
                                cur = 1;
                            ans[path.get(j)] = cur;
                            ans[path.get(j + 1)] = cur;
                        }
                    }
                }
                for (int i = 0; i < n; i++) {
                    if (adj.get(i).size() == 1 && !vis[i]) {
                        path.clear();
                        dfs(i);
                        if (path.size() % 2 == 1) {
                            out.println("NO");
                            return;
                        }
                        for (int j = 0; j + 1 < path.size(); j += 2) {
                            int cur = 0;
                            if (arr[path.get(j)] + arr[path.get(j + 1)] == b)
                                cur = 1;
                            ans[path.get(j)] = cur;
                            ans[path.get(j + 1)] = cur;
                        }
                    }
                }
                for (int i = 0; i < n; i++) {
                    if (!vis[i]) {
                        path.clear();
                        dfs(i);
                        if (path.size() % 2 == 1) {
                            out.println("NO");
                            return;
                        }
                        for (int j = 0; j < path.size(); j += 2) {
