                                cur = 1;
                            ans[path.get(j)] = cur;
                            ans[path.get(j + 1)] = cur;
                        }
                    }
                }
            }
            out.println("YES");
            for (int i : ans)
                out.print(i + " ");
            out.println();
        }
    }

