import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.ArrayDeque;
import java.util.Arrays;
import java.util.HashMap;
import java.util.Queue;
import java.util.StringTokenizer;

public class CF268_TwoSets {

	public static void main(String[] args) {

		MyScanner in = new MyScanner();

		int N = in.nextInt();
		int a = in.nextInt();
		int b = in.nextInt();

		int[] vals = new int[N];
		HashMap<Integer, Integer> val2Ind = new HashMap<Integer, Integer>();
		for (int i = 0; i < N; i++) {
			vals[i] = in.nextInt();
			val2Ind.put(vals[i], i);
		}

		int[] setAssignment = new int[N];
		int[] friendA = new int[N];
		int[] friendB = new int[N];
		Arrays.fill(setAssignment, -1);
		Arrays.fill(friendA, -1);
		Arrays.fill(friendB, -1);

		// Mark partners
		for (int i = 0; i < N; i++) {
			Integer friendAInd = val2Ind.get(a - vals[i]);
			if (friendAInd != null) {
				friendA[i] = friendAInd;
			}

			Integer friendBInd = val2Ind.get(b - vals[i]);
			if (friendBInd != null) {
				friendB[i] = friendBInd;
			}
		}

		// Find those with only one friend
		Queue<Integer> toProc = new ArrayDeque<Integer>();
		for (int i = 0; i < N; i++) {
			int friends = 0;
			if (friendA[i] != -1) {
				friends++;
			}
			if (friendB[i] != -1) {
				friends++;
			}
			if (friends == 1) {
				toProc.add(i);
			}
		}

		// Process the one frienders
		while (!toProc.isEmpty()) {

			int ind = toProc.poll();

			if (setAssignment[ind] != -1) {
				continue;
			}

			if (friendA[ind] != -1) {

				int other = friendA[ind];
				if (setAssignment[other] == -1) {
					setAssignment[ind] = 0;
					setAssignment[other] = 0;
					// Check other's friend
					if (friendB[other] != -1) {
						int otherOther = friendB[other];
						friendB[otherOther] = -1;
						toProc.add(otherOther);
					}
				} else {
					System.out.println("NO");
					return;
				}

			}

			else if (friendB[ind] != -1) {

				int other = friendB[ind];
				if (setAssignment[other] == -1) {
					setAssignment[ind] = 1;
					setAssignment[other] = 1;
					// Check other's friend
					if (friendA[other] != -1) {
						int otherOther = friendA[other];
						friendA[otherOther] = -1;
						toProc.add(otherOther);
					}
				} else {
					System.out.println("NO");
					return;
				}

			}

			else {
				System.out.println("NO");
				return;
			}

		}


		// Process those with two friends
		for(int i = 0; i < N; i++) {

			if(setAssignment[i] != -1) {
				continue;
			}

			if(friendA[i] == -1 && friendB[i] == -1) {
				System.out.println("NO");
				return;
			}

			// Only possibility should now be that both friends are possible
			setAssignment[i] = 0;
			setAssignment[friendA[i]] = 0;
		}

		// Print the result
		System.out.println("YES");
		StringBuilder sb = new StringBuilder();
		for(int i = 0; i < N; i++) {
			sb.append(setAssignment[i]);
			sb.append(" ");
		}
		sb.deleteCharAt(sb.length() - 1);
		System.out.println(sb);
	}

	public static class MyScanner {
		BufferedReader br;
		StringTokenizer st;

		public MyScanner() {
			br = new BufferedReader(new InputStreamReader(System.in));
		}

		String next() {
			while (st == null || !st.hasMoreElements()) {
				try {
					st = new StringTokenizer(br.readLine());
				} catch (IOException e) {
					e.printStackTrace();
				}
			}
			return st.nextToken();
		}

		int nextInt() {
			return Integer.parseInt(next());
		}

		long nextLong() {
			return Long.parseLong(next());
		}

		double nextDouble() {
			return Double.parseDouble(next());
		}

		String nextLine() {
			String str = "";
			try {
				str = br.readLine();
			} catch (IOException e) {
				e.printStackTrace();
			}
			return str;
		}

	}

}

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.*;

public class ProblemB {
    Map<Integer, List<int[]>> dest;

    private ProblemB() throws IOException {
        BufferedReader rd = new BufferedReader(new InputStreamReader(System.in));
        String h = rd.readLine();
        String[] q = h.split("\\s+");
        int a = Integer.parseInt(q[1]);
        int b = Integer.parseInt(q[2]);
        h = rd.readLine();
        q = h.split(" ");
        int n = q.length;
        int[] p = new int[n];
        for(int i=0;i<n;i++) {
            p[i] = Integer.parseInt(q[i]);
        }
        Set<Integer> pset = new HashSet<>();
        for(int x: p) {
            pset.add(x);
        }

        if(a == b) {
            boolean res = true;
            for(int x: p) {
                if(!pset.contains(a-x)) {
                    res = false;
                    break;
                }
            }
            out(res?"YES":"NO");
            if(res) {
                StringBuilder buf = new StringBuilder();
                for(int i=0;i<n;i++) {
                    if(i > 0) {
                        buf.append(' ');
                    }
                    buf.append('0');
                }
                out(buf);
            }
        } else {
            dest = new HashMap<>();
            boolean res = true;
            for(int x: p) {
                boolean aOk = pset.contains(a-x);
                boolean bOk = pset.contains(b-x);
                if(!aOk && !bOk) {
                    res = false;
                    break;
                } else {
                    if(aOk) {
                        addEdgeAndBack(x,a-x,0);
                    }
                    if(bOk) {
                        addEdgeAndBack(x,b-x,1);
                    }
                }
            }
            Set<Integer> aSet = new HashSet<>();
            if(res) {
                for(int x: p) {
                    List<int[]> e = getEdges(x);
                    if(e.size() == 1) {
                        int[] edge = e.get(0);
                        if(edge[0] == x) {
                            if(edge[1] == 0) {
                                aSet.add(x);
                            }
                        } else {
                            boolean odd = true;
                            int curA = edge[1];
                            int prev = x;
                            while(true) {
                                int cur = edge[0];
                                if(curA == 0 && odd) {
                                    aSet.add(prev);
                                    aSet.add(cur);
                                }
                                e = getEdges(cur);
                                if(e.size() == 1) {
                                    if(!odd && e.get(0)[0] != cur) {
                                        res = false;
                                    }
                                    break;
                                }
                                int other = e.get(0)[0] == prev?1:0;
                                edge = e.get(other);
                                if(edge[1] == curA) {
                                    res = false;
                                    break;
                                }
                                curA = 1-curA;
                                prev = cur;
                                odd = !odd;
                            }
                            if(!res) {
                                break;
                            }
                        }
                    }
                }
            }
            out(res?"YES":"NO");
            if(res) {
                StringBuilder buf = new StringBuilder();
                for(int i=0;i<n;i++) {
                    if(i>0) {
                        buf.append(' ');
                    }
                    buf.append(aSet.contains(p[i])?'0':'1');
                }
                out(buf);
            }
        }
    }

    private void addEdgeAndBack(int from, int to, int u) {
        addEdge(from, to, u);
        addEdge(to, from, u);
    }

    private void addEdge(int from, int to, int u) {
        List<int[]> edges = getEdges(from);
        for(int[] edge: edges) {
            if(edge[0] == to) {
                return;
            }
        }
        edges.add(new int[] { to, u });
    }

    private List<int[]> getEdges(int from) {
        List<int[]> ds = dest.get(from);
        if(ds == null) {
            ds = new ArrayList<>();
            dest.put(from, ds);
        }
        return ds;
    }

    private static void out(Object x) {
        System.out.println(x);
    }

    public static void main(String[] args) throws IOException {
        new ProblemB();
    }
}

