public class Main implements Runnable {
    public InputReader in;
    public PrintWriter out;

    public void solve() throws Exception {
        // solution goes here
        int N = in.nextInt();

        int[] houses = new int[N];
        boolean[] exist = new boolean[52];

        for (int i = 0; i < N; i++) {
            char c = in.nextChar();
            if ('a' <= c && c <= 'z') {
                houses[i] = 26 + (c - 'a');
            } else {
                houses[i] = (c - 'A');
            }
            exist[houses[i]] = true;
        }

        int[][] pokemons = new int[N][52];

        pokemons[0][houses[0]] = 1;

        for (int i = 1; i < N; i++) {
            System.arraycopy(pokemons[i-1], 0, pokemons[i], 0, pokemons[i].length);
            pokemons[i][houses[i]]++;
        }

        int uniques = 0;
        for(boolean bool : exist)
            if (bool)
                uniques++;

        if (uniques == 1) {
            out.print(1);
            return;
        }


        int last_variant = -1;
        for (int i = 0; i < N-1; i++) {
            if (pokemons[i][houses[i]] == pokemons[N-1][houses[i]]) {
                last_variant = i;
                break;
            }
        }

        int minimum = N;

        for (int i = 0; i <= last_variant; i++) {
            if (houses[i] == houses[i+1])
                continue;

            // binary search

            int low = i+1;
            int high = N-1;

            while (low < high) {
                int mid = (low + high) / 2;

                boolean allPresent = true;
                for (int j = 0; j < 52; j++) {
                    if (j != houses[i] && exist[j] && pokemons[mid][j] == pokemons[i][j]) {
                        allPresent = false;
                        break;
                    }
                }

                if (allPresent) {
                    high = mid; // infinite??
                } else {
                    low = mid + 1;
                }
            }

            minimum = min(minimum, low - i + 1);

        }

        out.print(minimum);
    }

