		for(int i=1;i<=n;i++)
		{
			int low=0,high=n-i+1;boolean got=false;
			while(low<high)
			{
				int mid=(low+high)>>1;
				boolean curr=true;
				for(int j=65;j<=90;j++)
				{
					if(v[j])
					{
						if(pre[j][i+mid]-pre[j][i-1]<=0)
