    }



    int[] gcd (int a, int b) {
        int[] res = new int[3];
        if (a == 0) {
            res[0] = b; res[1] = 0; res[2] = -1;
            return res;
        }
        res = gcd (b%a, a);
        int x = -(res[2] + (b / a) * res[1]);
        int y = - res[1];
        res[1] = x;
        res[2] = y;
        return res;
    }


    public void solve() throws IOException {
        int n = readInt();
        HashMap<Character,Integer> mapa = new HashMap<>();

        char[] s = readString().toCharArray();

        for(int i = 0; i < n; i++) {
            if(mapa.containsKey(s[i])) {
                int x = mapa.get(s[i]);
                mapa.replace(s[i], x + 1);
            }
            else mapa.put(s[i], 1);
        }

        int sz = mapa.size();
        mapa = new HashMap<>();
        int i = 0;
        while (mapa.size() < sz) {
            if(mapa.containsKey(s[i])) {
                int x = mapa.get(s[i]);
                mapa.replace(s[i], x + 1);
            }
            else mapa.put(s[i], 1);
            i++;
        }
        int ans = i;

        int left = 0;
        int right = i - 1;

        while(right < n) {
            while(left < right) {
                int y = mapa.get(s[left]);
                if(y == 1) mapa.remove(s[left]);
                else mapa.replace(s[left], y - 1);
                if(mapa.size() == sz) {
                    ans = Math.min(ans, right - left);
                    left++;
                }
                else {
                    left++;
                    break;
                }
            }

            right++;
            if(right < n) {
                if (mapa.containsKey(s[right])) {
                    int x = mapa.get(s[right]);
                    mapa.replace(s[right], x + 1);
                } else mapa.put(s[right], 1);
            }

        }

        out.print(ans);

    }
}

