		int n = nextInt();
		char[]a = next().toCharArray();
		int[]cnt = new int[256];
		for (int i = 0; i < n; i++) {
			cnt[a[i]]++;
		}
		int alldiff = 0;
		for (int i = 0; i < 256; i++) {
			if (cnt[i] > 0)
				alldiff++;
		}
		Arrays.fill(cnt, 0);
		int diff = 0, right = -1, ans = n+5;
		for (int i = 0; i < n; i++) {
			if (right < i) {
				cnt[a[i]]++;
				diff = 1;
				right = i;
			}
			while (right < n-1 && diff < alldiff) {
				right++;
				cnt[a[right]]++;
				if (cnt[a[right]]==1)
					diff++;
			}
			if (diff==alldiff && right-i+1 < ans) {
				ans = right-i+1;
			}
			cnt[a[i]]--;
			if (cnt[a[i]]==0)
				diff--;
		}
