    public void solve() {
        int n = in.nextInt();
        TreeMap<Character, Integer> map = new TreeMap<>();
        ArrayList<Integer> list = new ArrayList<>();
        String s = in.next();
        for (int i = 0; i < n; i++) {
            char ch = s.charAt(i);
            if (!map.containsKey(ch))
                map.put(ch, map.size());
            list.add(map.get(ch));
        }

        int l = 0;
        int ans = Integer.MAX_VALUE;
        int nad = map.size();
        int cnt[] = new int[n];

        for (int i = 0; i < list.size(); i++) {
            if (cnt[list.get(i)] == 0)
                nad--;
            cnt[list.get(i)]++;

            if (nad == 0) {
                ans = min(ans, i - l + 1);
                while (true) {
                    if (cnt[list.get(l)] == 1) {
                        ans = min(ans, i - l + 1);
                        cnt[list.get(l)]--;
                        l++;
                        nad++;
                        break;
                    } else {
                        cnt[list.get(l)]--;
                        l++;
                    }
                }
            }
        }

        out.print(ans);
    }

