	static class Solver{
		public void solve(InputReader in, PrintWriter out) {
			int n = in.nextInt();
			String s = in.next();
			HashMap<Character, Integer> map = new HashMap<>();
			for (int i = 0; i < n; ++ i) {
				map.put(s.charAt(i), 0);
			}
			int l = 0, r = 0, cnt = 0, ans = n;
			char c;
			while (l < n) {
				while (r < n && cnt < map.size()) {
					c = s.charAt(r);
					map.put(c, map.get(c) + 1);
					if (map.get(c) == 1) ++cnt;
					++r;
				}

				if (cnt == map.size() && r-l < ans)
					ans = r-l;

				c = s.charAt(l);
				map.put(c, map.get(c)-1);
				if (map.get(c) == 0) --cnt;
				++l;
			}
			out.println(ans);
		}
	}

