  void add(char c) {
    cc.put(c, cc.getOrDefault(c, 0) + 1);
  }

  void rem(char c) {
    Integer cnt = cc.get(c) - 1;
    if (cnt != 0) {
      cc.put(c, cnt);
    } else {
      cc.remove(c);
    }
  }

