    for (int i = 0, j = 0; i < n; i++) {
      while ((j < n) && (cc.size() < t)) {
        add(s[j]);
        j++;
      }

      if (cc.size() == t) {
        m = Math.min(m, j - i);
      }

      rem(s[i]);
    }

    println(m);
  }

