                if (operations[i]==k-1) list.add(i);
            }
            int[][] matr = new int[n+1][n+1];
            for (int i=0; i<=n; i++) {
                matr[i][0] = matr[i][i] = 1;
                if (i==0) continue;
                for (int j=1; j<=n; j++) {
                    matr[i][j] = (matr[i-1][j-1] + matr[i-1][j]) % MOD;
                }
            }
            int res = 0;
            for (int y=1; y<n; y++) {
                for (int x:list) {
                    if (x>y) break;
                    if (y==1 && x==1) continue;
                    res = (res + matr[y-1][x-1]) % MOD;
                }
            }
