       int n=ni();
       A=ni(); B=ni(); C=ni(); T=ni();
       a=new int[T+1];
       for(int i=1;i<=n;i++) a[ni()]++;
       long ans=0;
       for(int i=0;i<=T;i++){
           if(a[i]==0) continue;
