            i=0;
            while (temp-->0){
                int x= sc.nextInt();
                int y= sc.nextInt();
                arr[i++]=x*60+y;
            }
            boolean flag=false;
            if (arr[0]>=gap+1)
                out.println("0 0");
            else{
                for (i = 1; i < n; i++) {
                    if (arr[i]-arr[i-1]>=2*gap+2){
                        out.println((arr[i-1]+gap+1)/60+" "+(arr[i-1]+gap+1)%60);
                        flag=true;
                        break;
                    }
