    static int getmax(String s,int n)
    {
        int i,l=s.length(),c[]=new int[256];
        for(i=0;i<l;i++)
        c[s.charAt(i)]++;

        int max=0;
        for(i=0;i<256;i++)
        max=Math.max(c[i],max);
        //System.out.println(max);
        if(n>l-max)
        {
            if(max==l && n==1 && l!=1) max--;  //we cant have n only if all characters are equal and we must make 1 move
            else max=l;
        }
        else max+=n;
        //System.out.println(max);
        return max;
    }
}

