    		int base=(l/currprime)*currprime;
    		if(base<l) {
    			base+=currprime;
    		}
    		for(int j=base;j<=r;j+=currprime) {
    			p[j-l]=false;
    		}


    		if(base==currprime) {
    			p[base-l]=true;
    		}

    	}
    	for(int i=0;i<=r-l;i++) {
    		if(p[i])
    			isprime.add(i+l);
    	}
    	return isprime;
    }


    public static void main(String[] args) 
    { 
        FastReader sc=new FastReader(); 
        try{
           long n=sc.nextLong();
           long m=sc.nextLong();
           long a=sc.nextLong();
           long b=sc.nextLong();
           long ans1=n/m * m + m - n;
           long ans2=n%m;
           long ans=Long.min(ans1*a,ans2*b);
           System.out.println(ans);

        }catch(Exception e){
            return;
        }
    } 
}

