				cnt[1][0]--;
			}
			if (nxt.equals("XL")) {
				cnt[1][1]--;
			}
			if (nxt.equals("XXS")) {
				cnt[2][0]--;
			}
			if (nxt.equals("XXL")) {
				cnt[2][1]--;
			}
			if (nxt.equals("XXXS")) {
				cnt[3][0]--;
			}
			if (nxt.equals("XXXL")) {
				cnt[3][1]--;
			}
		}

		int ans = 0;
		for (int i = 1; i <= 3; i++) {
			ans += Math.abs(cnt[i][0]);
		}

		int max = 0;
		for (int i = 0; i < 3; i++) {
			max = Math.max(max, Math.abs(cnt[0][i]));
		}
		ans += max;
		printer.println(ans);
		printer.close();
	}
}

