        public static void solve(FastReader in, PrintWriter out) {
            int n = in.nextInt();
            HashMap<String , Integer> hm1 = new HashMap<>();
            HashMap<String , Integer> hm2 = new HashMap<>();

            for(int i=0;i<n;i++){
                String val = in.next();
                if(hm1.containsKey(val)){
                    hm1.put(val, hm1.get(val)+1);
                }else{
                    hm1.put(val,1);
                }
            }

            for(int i=0;i<n;i++){
