		on[0] = 0;
		off[0] = 0;

		for(int i = 1; i<n; i++)
		{
		    if(i%2==1)
		      { on[i] = on[i-1] + arr[i]-arr[i-1]; off[i] = off[i-1]; }
		    if(i%2==0)
		      { off[i] = off[i-1] + arr[i]-arr[i-1]; on[i] = on[i-1]; }
		}

		long max = on[n-1];

		for(int i = 1; i<n; i++)
		{
		    long curr = on[i-1] + (off[n-1]-off[i]) + arr[i]-arr[i-1]-1;
		    if(curr>max)
		    	max = curr;
		}

		return max;
	}

