public class Segment
	{
		private Node[] tree;
		private int[] lazy;
		private int size;
		private int n;
		private int[] base;

		private class Node
		{
			private int on;
			private int off;
		}

		public Segment(int n, int[] arr)
		{
			this.base=arr;
			int x = (int) (Math.ceil(Math.log(n) / Math.log(2)));
			size = 2 * (int) Math.pow(2, x) - 1;
			tree = new Node[size];
			lazy = new int[size];
			this.n = n;
			//this.set = set1;
			build(0, 0, n - 1);
		}

		public void build(int id, int l, int r)
		{
			if (l == r)
			{
				tree[id] = new Node();
				if(base[l] == 1)
					tree[id].on++;
				else
					tree[id].off++;
				return;
			}
			int mid = ((l + r)>>1);
			build((id<<1)|1, l, mid);
			build((id<<1)+2, mid + 1, r);
			tree[id] = merge(tree[(id<<1)|1], tree[(id<<1)+2]);
			//System.out.println(l+" "+r+" "+tree[id].l+" "+tree[id].r+" "+tree[id].ans);
		}
		public Node merge(Node n1, Node n2) {
			Node ret = new Node();
			if(n1 == null && n2 == null)
				return null;
			else if(n1 == null) {
				ret.on = n2.on;
				ret.off = n2.off;
			}
			else if(n2 == null) {
				ret.on = n1.on;
				ret.off = n1.off;
			}
			else {
				ret.on = n1.on+n2.on;
				ret.off = n2.off + n1.off;
			}
			return ret;
		}
		public int query(int l, int r)
		{
			Node ret = queryUtil(l, r, 0, 0, n - 1);
			if(ret == null) {
				return 0;
			}
			else
				return ret.on;
		}

		private Node queryUtil(int x, int y, int id, int l, int r)
		{
			if (l > y || x > r)
				return null;
			if (x <= l && r <= y)
			{
				//shift(id,l,r);
				return tree[id];
			}
			int mid = ((l + r)>>1);
			shift(id,l,r);
			Node q1 = queryUtil(x, y, (id<<1)|1, l, mid);
			Node q2 = queryUtil(x, y, (id<<1)+2, mid + 1, r);
			return merge(q1, q2);
		}

		public void update(int x, int y, int c) {
			update1(x, y, c, 0, 0, n-1);
		}

		private void update1(int x, int y, int colour, int id, int l, int r)
		{
			//System.out.println(l+" "+r+" "+x);
			if (x > r || y < l)
				return;
			if (x <= l && r <= y)
			{
				lazy[id]++;
//				lazy[id] %= 2;
				switchNode(tree[id]);
				return;
			}
			int mid = ((l + r)>>1);
			//shift(id);
			if(y<=mid)
				update1(x, y, colour, (id<<1)|1, l, mid);
			else if(x>mid)
				update1(x, y, colour, (id<<1)+2, mid + 1, r);
			else {
				update1(x, y, colour, (id<<1)|1, l, mid);
				update1(x, y, colour, (id<<1)+2, mid + 1, r);
			}
			tree[id] = merge(tree[(id<<1)|1], tree[(id<<1)+2]);	
		}
		private void shift(int id,int l, int r)
		{
			lazy[id] %= 2;
			if(lazy[id] != 0) {
				if(l != r) {
					lazy[(id<<1)|1] += lazy[id];
					lazy[(id<<1)+2] += lazy[id];
					switchNode(tree[(id<<1)+2]);
					switchNode(tree[(id<<1)|1]);
				}
				//switchNode(tree[(id<<1)+2]);
				lazy[id] = 0;
			}
		}
		private void switchNode(Node d) {
			d.on ^= d.off;
			d.off ^= d.on;
			d.on ^= d.off;
		}
	}

