                l.add(u);
                int x=l.get(0);
                int z=l.get(1);
                ArrayList<Integer> l1=new ArrayList<>();
                int c=0;
                int flag=0;
                while(true)
                {
                    l1.add(x);
                    c++;
                    set.add(x);
                    if(x==z)
                    {
                        break;
                    }
                    x=adj[x].get(0);
                    if(c>n)
                    {
                        flag=1;
                        break;
                    }
                }
                if(flag==0)
                list.add(l1);
            }
            else
            {
                set.add(u);
            }
            return;
        }
        else
        {
            dfsUtil(adj,v,visit,list,set,n);
        }
