	public void solve() throws Exception {
		int n = sc.nextInt();
		Points points[] = new Points[n];
		for(int i=0;i<n;i++) {
			points[i]=new Points(sc.nextInt(),sc.nextInt());
		}
		Arrays.parallelSort(points,(a,b)->(a.x-b.x));
		int left[]=new int[n];
		int right[]=new int[n];
		for(int i=0;i<n;i++) {
			left[i]=points[i].x;
			right[i]=points[i].y;
		}
		sort(left);
		sort(right);
		int max=0;
		for(int i=0;i<n;i++) {
			int max1=left[n-1];
			int max2=right[0];
			if(points[i].x==left[n-1]) {
				max1=left[n-2];
			}
			if(points[i].y==right[0]) {
				max2=right[1];
			}
			max=Math.max(max, max2-max1);

		}
		out.println(max);

	}

	class Points {
		int x,y;

		public Points(int x, int y) {
			super();
			this.x = x;
			this.y = y;
		}

	}

	static void sort(int[] a) {
		ArrayList<Integer> l = new ArrayList<>();
		for (int i : a)
			l.add(i);
		Collections.sort(l);
		for (int i = 0; i < a.length; i++)
			a[i] = l.get(i);
	}

	static long gcd(long a, long b) {
		if (a == 0)
			return b;
		return gcd(b % a, a);
	}

	static long ncr(int n, int r, long p) {
		if (r > n)
			return 0l;
		if (r > n - r)
			r = n - r;

		long C[] = new long[r + 1];

		C[0] = 1;

		for (int i = 1; i <= n; i++) {

			for (int j = Math.min(i, r); j > 0; j--)
				C[j] = (C[j] + C[j - 1]) % p;
		}
		return C[r] % p;
	}

	public long power(long x, long y, long p) {
		long res = 1;
		// out.println(x+" "+y);
		x = x % p;
		if (x == 0)
			return 0;

		while (y > 0) {
			if ((y & 1) == 1)
				res = (res * x) % p;
			y = y >> 1;
			x = (x * x) % p;
		}
		return res;
	}

