   static long modPow(long a, long x, long p) {
    //calculates a^x mod p in logarithmic time.
    long res = 1L;
    while(x > 0) {
        if( x % 2 != 0) {
            res = (res * a) % p;
        }
        a = (a * a) % p;
        x /= 2;
    }
    return res;
}



  static long modInverse(long a, long p) {
    //calculates the modular multiplicative of a mod p.
    //(assuming p is prime).
    return modPow(a, p-2, p);
