static long modBinomial(long n, long r, long p) {
// calculates C(n,r) mod p (assuming p is prime).

  if(n < r) return 0L ; 

    long num = factorial[(int)(n)] ;

    long den = (factorial[(int)(r)]*factorial[(int)(n-r)]) %  p ;


