import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.PrintWriter;
import java.util.StringTokenizer;


public class pr1073B {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        PrintWriter out = new PrintWriter(System.out);

        int n = Integer.parseInt(br.readLine());

        int[] a = new int[n];
        int[] b = new int[n];

        StringTokenizer st = new StringTokenizer(br.readLine());

        for (int i = 0; i < n; i++) {
            a[i] = Integer.parseInt(st.nextToken());
        }
        st = new StringTokenizer(br.readLine());
        for (int i = 0; i < n; i++) {
            b[i] = Integer.parseInt(st.nextToken());
        }

        solve(n, a, b, out);
        out.flush();
        out.close();
    }

    private static void solve(int n, int[] a, int[] b, PrintWriter out) {
        boolean[] book = new boolean[n+1];
        boolean f;
        int j1 = 0, j2 = 0;
        for (int i = 0; i < n; i++) {
            f = false;
            int num = b[i];
            if(!book[num]) {
                f = true;
                j1 = j2;
                for (;j2 < n; j2++) {
                    book[a[j2]] = true;
                    if (a[j2] == num) {
                        j2++;
                        break;
                    }
                }
            }
            out.print(f ? j2-j1 + " ": 0 + " ");
        }
    }
}

import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws IOException {
	BufferedReader in = new BufferedReader(new InputStreamReader(System.in));
	int[] data = parseInts(in.readLine().split(" "));
	int n = data[0];
	int m = data[1];
	List<Integer> riders = new ArrayList<>(n);
	NavigableMap<Integer, Integer> drivers = new TreeMap<>();	
	{
	    int[] xs = parseInts(in.readLine().split(" "));
	    int[] ts = parseInts(in.readLine().split(" "));
	    for (int i = 0; i < ts.length; i++) {
		if (ts[i] == 1) {
		    drivers.put(xs[i], 0);
		} else {
		    riders.add(xs[i]);
		}
	    }
	}
	for (int r : riders) {
	    int distLeft = Integer.MAX_VALUE;
	    Integer left = drivers.lowerKey(r);
	    if (left != null) {
		distLeft = r - left;
	    }
	    int distRight = Integer.MAX_VALUE;
	    Integer right = drivers.higherKey(r);
	    if (right != null) {
		distRight = right - r;
	    }
	    if (distLeft <= distRight) {
		drivers.put(left, drivers.get(left) + 1);
	    } else {
		drivers.put(right, drivers.get(right) + 1);
	    }
	}
	PrintWriter out = new PrintWriter(System.out);
	Iterator<Integer> it = drivers.values().iterator();
	out.print(it.next());
	while (it.hasNext()) {
	    out.print(' ');
	    out.print(it.next());
	}
	out.println();
	out.close();
    }

