    }

    static class TaskF {
        public void solve(int testNumber, InputReader in, PrintWriter out) {
            int n = in.nextInt();
            long[] len = new long[n];
            for (int i = 0; i < n; ++i) {
                len[i] = in.nextLong();
            }
            String types = in.next();
            long am1 = 0;
            long am2 = 0;
            boolean have3 = false;
            boolean have5 = false;
            long res = 0;
            for (int i = 0; i < n; ++i) {
                long x = len[i];
                switch (types.charAt(i)) {
                    case 'L': {
                        res += x;
                        {
                            long by = Math.min(am1, x);
                            am1 -= by;
                            x -= by;
                            res += by;
                        }
                        {
                            long by = Math.min(am2, x);
                            am2 -= by;
                            x -= by;
                            res += 2 * by;
                        }
                        if (have3) {
                            long by = x;
                            x -= by;
                            res += 3 * by;
                        }
                        if (have5) {
                            long by = x;
                            x -= by;
                            res += 5 * by;
                        }
                        if (x != 0) throw new RuntimeException();
                        break;
                    }

                    case 'W': {
                        res += 2 * x;
                        am1 += x;
                        have3 = true;
                        break;
                    }

                    case 'G': {
                        long y = Math.min(am1, x);
                        res += 2 * y;
                        x -= y;
                        am2 += 2 * y;
                        am1 -= y;

                        res += 3 * x;
                        am2 += x;
                        have5 = true;
                    }
                }
            }

            out.println(res);
        }

    }

