				ans += 2*L[i];
				s1 += L[i];
				xslope = 3;
			}else {
				long need = L[i];
				ans += L[i];
				{
					long use = Math.min(s1, need);
					s1 -= use; need -= use;
					ans += use;
				}
				{
					long use = Math.min(s2, need);
					s2 -= use; need -= use;
					ans += 2*use;
				}
				{
					ans += xslope*need;
				}
			}
		}
