	    public static long nCrModP(long n, long r,long p)
	    {
	          if (n<r) 
	              return 0;

	        if (r == 0)
	            return 1;

	        long[] fac = new long[(int)(n) + 1];
	        fac[0] = 1;

	        for (int i = 1; i <= n; i++)
	            fac[i] = fac[i - 1] * i % p;

	        return (fac[(int)(n)] * modInverse(fac[(int)(r)], p)
	                % p * modInverse(fac[(int)(n - r)], p)
	                % p)
	            % p;
	    }

