    static class TaskA {
        public void call(InputReader in, PrintWriter out) {
            int n, q;
            n = in.nextInt();
            q = in.nextInt();

            ArrayDeque<Integer> arrayDeque = new ArrayDeque<>();
            Map<Integer, answer> map = new HashMap<>();

            int a, b, c = 0, max = Integer.MIN_VALUE;

            for (int i = 0; i < n; i++) {
                a = in.nextInt();
                arrayDeque.add(a);
                max = Math.max(max, a);
            }

            for (int i = 0; i < n; i++) {
                if(arrayDeque.getFirst() == max){
                    break;
                }

                a = arrayDeque.removeFirst();
                b = arrayDeque.removeFirst();

                map.put(i+1,new answer(a,b));
                c = i+1;

                if(a>b){
                    arrayDeque.addFirst(a);
                    arrayDeque.addLast(b);
                }
                else{
                    arrayDeque.addFirst(b);
                    arrayDeque.addLast(a);
                }

            }

            int[] arr = new int[n];

            for (int i = 0; i < n; i++) {
                arr[i] = arrayDeque.removeFirst();
            }

            long m;
            for (int i = 0; i < q; i++) {
                m = in.nextLong();

                if(m<=c){
                    out.println(map.get((int)m).a +" "+map.get((int)m).b);
                }
                else{
                    m-=c;
                    m = m%(n-1);
                    if(m==0){
                        m = n-1;
                    }
                    out.println(max+" "+arr[(int)m]);
                }


            }

        }
    }

    static int gcd(int a, int b)
    {
        if (a == 0)
            return b;
        return gcd(b % a, a);
    }

    static int lcm(int a, int b)
    {
        return (a / gcd(a, b)) * b;
    }

    static class answer implements Comparable<answer>{
        int a;
        int b;

        public answer(int a, int b) {
            this.a = a;
            this.b = b;
        }

        @Override
        public int compareTo(answer o) {
            return this.a - o.a;
        }
