    static int process(Queue<Long> values, long bucket, int offSet, long k) {
        int ans = 0;
        while (!values.isEmpty()) {
            long v = values.peek();
            long b = (v - offSet + k - 1) / k;
            if (b == bucket) {
                ans++;
                values.poll();
            } else {
                break;
            }
        }
        return ans;
