			p2Win();
			return;
		}

		int sameCnt = 0;
		for(int i = 0; i < N-1; i++) {
			if(ar[i] == ar[i+1]) sameCnt++;
		}

		if(sameCnt > 0) {
			for(int i = 0; i < N-1; i++) {
				if(ar[i] == ar[i+1]) {
					ar[i]--;
					break;
				}
			}
