		long min = 0;
		long tot = 0;
		for(int i = 0; i < N; i++) {
			min += i;
			tot += ar[i];
		}

		if((tot-min)%2 == 0) {
			if(sameCnt == 0) p2Win();
			else p1Win();
		}
