public class Main {
    public void exec() {
        int n = stdin.nextInt();
        int[] a = stdin.nextIntArray(n);
        List<Node> nodes = Arrays.stream(a).mapToObj(v -> {
            Node node = new Node();
            node.value = v;
            return node;
        }).collect(Collectors.toList());

        int maxValue = -1;
        int maxIndex = -1;
        for (int i = 0, len = nodes.size(); i < len; i++) {
            Node node = nodes.get(i);

            if (maxValue < node.value) {
                maxValue = node.value;
                maxIndex = i;
            }

            if (i == 0) {
                node.right = nodes.get(i+1);
            } else if (i == len - 1) {
                node.left = nodes.get(i-1);
            } else {
                node.left = nodes.get(i-1);
                node.right = nodes.get(i+1);
            }
        }

        Node node = nodes.get(maxIndex);
        for (int i = 0; i < n-1; i++) {
            if (node.left != null && node.value == node.left.value+1) {
                node.left.right = node.right;
                node = node.left;
            } else if (node.right != null && node.value == node.right.value+1) {
                node.right.left = node.left;
                node = node.right;
            } else {
                stdout.println("NO");
                return ;
            }
        }
        stdout.println("YES");
    }

