	static int next(long[] arr, long target)  
    {  
        int start = 0, end = arr.length - 1;  

        int ans = -1;  
        while (start <= end) {  
            int mid = (start + end) / 2;  

            // Move to right side if target is  
            // greater.  
            if (arr[mid] < target) {
                start = mid + 1;  
            }  

            // Move left side.  
            else {  
                ans = mid;  
                end = mid - 1;  
            }  
        }  
        return ans;  
    } 

	static int prev(long[] arr, long target)  
    {  
        int start = 0, end = arr.length - 1;  

        int ans = -1;  
        while (start <= end) {  
            int mid = (start + end) / 2;  

            // Move to left side if target is  
            // lesser.  
            if (arr[mid] > target) {
                end = mid - 1;  
            }  

            // Move right side.  
            else {  
                ans = mid;  
                start = mid + 1;  
            }  
        }  
        return ans;  
    } 

	static long power(long x, long y, long p) 
    { 
        long res = 1; 
        x = x % p; 

        while (y > 0) 
        { 
            if (y % 2 == 1) 
                res = (res * x) % p; 
            y = y >> 1;
            x = (x * x) % p; 
        } 
        return  res; 
    } 
    static long modInverse(long n, long p) 
    { 
        return power(n, p-2, p); 
    } 
    static long nCrModP(long n, long r, 
                                    long p) 
    { 
        if(r>n)
        	return 0;
    	if (r == 0) 
            return 1; 
        long[] fac = new long[(int) (n+1)]; 
        fac[0] = 1; 
        for (int i = 1 ;i <= n; i++) 
            fac[i] = fac[i-1] * i % p;
        return (fac[(int) n]* modInverse(fac[(int) r], p) 
                % p * modInverse(fac[(int) (n-r)], p) 
                                    % p) % p; 
    } 
