    static class BPhoenixAndPuzzle {
        public void solve(int testNumber, InputReader in, OutputWriter out) {
            int n = in.nextInt();
            if (n % 2 == 1) {
                out.println("NO");
                return;
            }
            n /= 2;
            int h = (int) Math.sqrt(n + 0.5);
            if (h * h == n) {
                out.println("YES");
                return;
            }
            if (n % 2 == 1) {
                out.println("NO");
                return;
            }
            n /= 2;
            h = (int) Math.sqrt(n + 0.5);
            if (h * h == n) {
                out.println("YES");
            } else out.println("NO");
        }

    }

