	static boolean sq(long x) {
		long l = 1;
		long r = (int)Math.sqrt(1e16)+1;
		while (l+1<r) {
			long m = (l+r)>>1;
			if (m * m > x) r = m;
			else l = m;
		}
		return l*l == x;
	}

	static boolean solve(long x) {
		if ((x&1)==1) return false;
		if ((x & (x-1)) == 0) return true;
		long num = 2;
		while (num < x && x % num == 0) {
			if (sq(x/num)) return true;
			num*=2;
		}
		return false;
	}

