		q.offer(start);
		HashSet<Integer> visited=new HashSet<>();

		System.out.print(q.peek()+"\n");

		while(!q.isEmpty()) {
			int parent=q.poll();

			if(visited.contains(parent)) {
				continue;
			}
			visited.add(parent);
			int flag=0;

			for(int child:tree.get(parent)) {
				if(!visited.contains(child)) {
					q.offer(child);
					System.out.print(child+" ");
					flag=1;
				}
			}

			if(flag==0) {
				continue;
			}
			System.out.println();
		}
	}

