		int[] z=new int[s.length()];
		 int l=0,r=0;

		 for(int i=1;i<s.length();i++) {

			 if(i <= r) {
				 z[i]=Math.min( z[i-l] , r-i+1);
			 }
			 while(i+z[i] < s.length() && s.charAt(z[i])==s.charAt(i+z[i])) {
				 z[i]++;
