        for (int i=1; i*i <= n; i++) 
        { 
            if (n%i==0) 
            { 
                if (n/i == i) 
                    div.add(i); 
                else { 
                    div.add(i);
                    div.add(n/i);
                }
            } 
        }

        return div;
    }

    static long gcd(long x,long y) {
    	return (y==0?x:gcd(y,x%y));
    }

